        if (codeStyle == ktlint_official || isFirstParameterOfFunctionLiteralPrecededByNewLine()) {
            // val fieldExample =
            //      LongNameClass {
            //              paramA,
            //              paramB,
            //              paramC ->
            //          ClassB(paramA, paramB, paramC)
            //      }
            indentConfig.indent.repeat(2)
        } else if (isFunctionLiteralOnDifferentLineThanFunctionCall()) {
            // When the lambda opening brace is on a different line from the function call,
            // use double indent instead of alignment:
            // combine(
            //     Any(),
            //     Any()
            // ) { a,
            //         b ->
            //     TODO()
            // }
            indentConfig.indent.repeat(2)
        } else if (hasFunctionCallArgumentsBeforeLambda()) {
            // When there are function arguments before the lambda, use double indent
            // instead of alignment (as the alignment calculation is based on function name only):
            // combine(Any(), Any()) { a,
            //         b ->
            //     TODO()
            // }
            indentConfig.indent.repeat(2)
        } else {
            // Allow default IntelliJ IDEA formatting:
            // val fieldExample =
            //     LongNameClass { paramA,
            //                     paramB,
            //                     paramC ->
            //         ClassB(paramA, paramB, paramC)
            //     }
            parent(CALL_EXPRESSION)
                ?.let { callExpression ->
                    val textBeforeFirstParameter =
                        callExpression.findChildByType(REFERENCE_EXPRESSION)?.text +
                            " { "
                    " ".repeat(textBeforeFirstParameter.length)
                }
                ?: indentConfig.indent.repeat(2)
        }"}

