193→    private fun wrapParameterInList(
194→        newIndentLevel: Int,
195→        child: ASTNode,
196→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
197→        autoCorrect: Boolean,
198→    ) {
199→        val indent = "\n" + indentConfig.indent.repeat(newIndentLevel)
200→        when (child.elementType) {
201→            LPAR -> {
202→                val prevLeaf = child.prevLeaf()
203→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
204→                    emit(child.startOffset, errorMessage(child), true)
205→                    if (autoCorrect) {
206→                        prevLeaf.delete()
