        parent(FUNCTION_LITERAL)
            ?.findChildByType(VALUE_PARAMETER_LIST)
            ?.prevSibling { it.textContains('\n') } != null

    private fun ASTNode.isFunctionLiteralOnDifferentLineThanFunctionCall(): Boolean =
        parent(FUNCTION_LITERAL)
            ?.findChildByType(LBRACE)
            ?.let { lbrace ->
                parent(CALL_EXPRESSION)
                    ?.findChildByType(REFERENCE_EXPRESSION)
                    ?.let { referenceExpression ->
                        // Check if there's a newline between the function reference and the opening brace
                        var currentNode: ASTNode? = referenceExpression.nextLeaf()
                        while (currentNode != null && currentNode != lbrace) {
                            if (currentNode.textContains('\n')) {
                                return true
                            }
                            currentNode = currentNode.nextLeaf()
                        }
                        false
                    }
            } ?: false

