import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class Issue1756Test {
    private val indentationRuleAssertThat =
        KtLintAssertThat.assertThatRule { IndentationRule() }

    @Test
    fun `Issue 1756 - Format lambda parameters on multiple lines with non-ktlint_official code style`() {
        val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
              c(a, b)
            }

            class Foo {
              fun foo() {
                combine(
                  Any(),
                  Any()
                ) { a,
                          b ->
                  TODO()
                }
              }
            }
            """.trimIndent()
        val formattedCode =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
              c(a, b)
            }

            class Foo {
              fun foo() {
                combine(
                  Any(),
                  Any()
                ) { a,
                        b ->
                  TODO()
                }
              }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 1756 - Format lambda parameters on multiple lines with ktlint_official code style`() {
        val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                c(a, b)
            }

            class Foo {
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                              b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                c(a, b)
            }

            class Foo {
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                            b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 1756 - Lambda on same line as function call should still use alignment`() {
        val code =
            """
            class Foo {
              fun foo() {
                combine(Any(), Any()) { a,
                                        b ->
                  TODO()
                }
              }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue 1756 - Lambda with parameters on newline after opening brace`() {
        val code =
            """
            class Foo {
              fun foo() {
                combine(
                  Any(),
                  Any()
                ) {
                        a,
                        b ->
                  TODO()
                }
              }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
            .hasNoLintViolations()
    }
}
"}

